<?php
declare(strict_types=1);
namespace App\Core\Reports;
final class EcosistemaMarketingFunnelReportService{public function __construct(private readonly EcosistemaMarketingFunnelReportRepository $repository){}
public function build(int $tenantId,array $query): array{$today=(new \DateTimeImmutable('today'))->format('Y-m-d');$from=(string)($query['from']??$today);$to=(string)($query['to']??$today);if(!$this->validDate($from)){$from=$today;}if(!$this->validDate($to)){$to=$today;}if($from>$to){[$from,$to]=[$to,$from];}$campaignId=$this->positiveIntOrNull($query['campaign_id']??null);$landingId=$this->positiveIntOrNull($query['landing_id']??null);$result=['filters'=>['from'=>$from,'to'=>$to,'campaign_id'=>$campaignId,'landing_id'=>$landingId],'campaigns'=>[],'landings'=>[],'funnel'=>['clicks'=>0,'visits'=>0,'submissions'=>0,'leads'=>0,'conversions'=>0],'conversion_rates'=>['visit_rate'=>0.0,'submission_rate'=>0.0,'lead_rate'=>0.0,'conversion_rate'=>0.0],'mode'=>'read-only'];if($tenantId<=0){return $result;} $result['campaigns']=array_map(fn(array $r): array=>['id'=>(int)($r['id']??0),'name'=>(string)($r['name']??''),'code'=>(string)($r['code']??''),'status'=>(string)($r['status']??'')],$this->repository->listCampaigns($tenantId));$result['landings']=array_map(fn(array $r): array=>['id'=>(int)($r['id']??0),'name'=>(string)($r['name']??''),'slug'=>(string)($r['slug']??''),'status'=>(string)($r['status']??'')],$this->repository->listLandings($tenantId));$result['funnel']=$this->repository->funnelCounts($tenantId,$from,$to,$campaignId,$landingId);$clicks=max(0,(int)($result['funnel']['clicks']??0));$visits=max(0,(int)($result['funnel']['visits']??0));$subs=max(0,(int)($result['funnel']['submissions']??0));$leads=max(0,(int)($result['funnel']['leads']??0));$conv=max(0,(int)($result['funnel']['conversions']??0));$result['conversion_rates']=['visit_rate'=>$clicks>0?round(($visits/$clicks)*100,2):0.0,'submission_rate'=>$visits>0?round(($subs/$visits)*100,2):0.0,'lead_rate'=>$subs>0?round(($leads/$subs)*100,2):0.0,'conversion_rate'=>$leads>0?round(($conv/$leads)*100,2):0.0];return $result;}
private function positiveIntOrNull(mixed $value): ?int{if($value===null||$value===''){return null;} if(is_numeric($value)!==true){return null;} $parsed=(int)$value;return $parsed>0?$parsed:null;}
private function validDate(string $date): bool{$dt=\DateTimeImmutable::createFromFormat('Y-m-d',$date);return $dt!==false&&$dt->format('Y-m-d')===$date;}}
